issuesFound.explanation:
The hamburger button (`_trigger`) controls the off‑canvas drawer (`_drawer`) but never receives an `aria-controls` attribute that points to the drawer’s `id`. Assistive technologies therefore cannot associate the button with the region it shows/hides.  
Fix (add to `mobileNav.init` after the element is selected):  
```javascript
_trigger  = qs(SELECTORS.navToggle);
_drawer   = qs(SELECTORS.navDrawer || SELECTORS.primaryNav);
if (_trigger && _drawer) {
  const drawerId = srUtils.ensureId(_drawer, 'nav-drawer');
  setAttr(_trigger, 'aria-controls', drawerId);
  setAttr(_trigger, 'aria-expanded', 'false'); // also initialise state (see Issue 8)
}
```

The period‑selection buttons (`_periodBtns`) receive a visual “active” class but never expose their pressed state via `aria‑pressed`, leaving screen‑reader users unaware of the current billing period.  
Fix (add to `_syncToggleState`):  
```javascript
function _syncToggleState(period) {
  if (!_periodBtns) return;
  _periodBtns.forEach(btn => {
    const isActive = btn.getAttribute('data-period') === period;
    toggleClass(btn, CSS.active, isActive);
    setAttr(btn, 'aria-pressed', String(isActive)); // ← add
  });
  // …rest of function unchanged
}
```

`inlineValidator.validate` marks fields as invalid only by adding CSS classes and error messages; it never adds `aria-invalid="true"`. Assistive technologies therefore cannot convey the error state.  
Fix (inside `inlineValidator.validate` after determining `result`):  
```javascript
if (!result.valid) {
  setAttr(field, 'aria-invalid', 'true');   // ← add
  srUtils.markInvalid(field, errorEl);
} else {
  removeAttr(field, 'aria-invalid');       // ← add
  srUtils.markValid(field, errorEl);
}
```

`_updateCountBadge` changes the product‑count badge text but does not announce the new total to screen‑reader users, so they are unaware that the result set changed.  
Fix (add a hidden live region and announce after updating):  
```javascript
let _countLive; // module‑level variable
function _ensureLive() {
  if (!_countLive) {
    _countLive = createElement('div', {
      class: 'sr-only',
      role: 'status',
      'aria-live': 'polite',
    });
    _countBadge.parentNode.appendChild(_countLive);
  }
}
function _updateCountBadge(count) {
  if (!_countBadge) return;
  _countBadge.textContent = String(count);
  _countBadge.setAttribute('aria-label',
    `${count} product${count !== 1 ? 's' : ''}`);
  _ensureLive();
  _countLive.textContent = `${count} products shown`;
}
```

Changing the billing period updates prices but provides no audible feedback, leaving screen‑reader users unaware of the switch.  
Fix (add a live‑region announcement at the end of `setPeriod`):  
```javascript
function setPeriod(period, animate) {
  // …existing code…
  _syncToggleState(period);
  // …update cards…
  requestAnimationFrame(() => { _pricingState.animating = false; });

  // ---- new ----
  const periodLabel = BILLING_PERIODS[period].label;
  liveRegion.announce(`Billing period set to ${periodLabel}`);
  // -------------- 
}
```

When no products match the filter, `_updateEmptyState` simply shows the element; there is no live‑region to inform screen‑reader users that the result set is empty.  
Fix (add a hidden live region and announce when the empty state becomes visible):  
```javascript
let _emptyLive; // module‑level
function _ensureEmptyLive() {
  if (!_emptyLive) {
    _emptyLive = createElement('div', {
      class: 'sr-only',
      role: 'status',
      'aria-live': 'polite',
    });
    _emptyState.parentNode.appendChild(_emptyLive);
  }
}
function _updateEmptyState(count) {
  if (!_emptyState) return;
  if (count === 0) {
    _emptyState.removeAttribute('hidden');
    _ensureEmptyLive();
    _emptyLive.textContent = STRINGS.noProductsFound || 'No products match your filters';
  } else {
    _emptyState.setAttribute('hidden', '');
  }
}
```

When a dropdown is registered, the code adds `aria-controls` only if the trigger lacks it **and** the panel has an `id`. However, some panels are generated without an `id`, leaving the trigger without `aria-controls`. This breaks the relationship for assistive technologies.  
Fix (ensure the panel always has an `id` before setting the attribute):  
```javascript
function register(trigger, panel) {
  if (!isElement(trigger) || !isElement(panel)) return;
  if (_getInstance(trigger)) return;

  // Ensure panel has an id
  const panelId = srUtils.ensureId(panel, 'dropdown-panel');
  // Ensure trigger references it
  if (!trigger.getAttribute('aria-controls')) setAttr(trigger, 'aria-controls', panelId);
  // …rest unchanged
}
```

